import{_ as a,o as t,c as p,j as r,a as o,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"爱尔夫罗伊德（ELFROID）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/爱尔夫罗伊德（ELFROID）.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/爱尔夫罗伊德（ELFROID）.md"}'),n={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/爱尔夫罗伊德（ELFROID）.md"};function s(b,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"爱尔夫罗伊德-elfroid",tabindex:"-1"},[o("爱尔夫罗伊德（ELFROID） "),r("a",{class:"header-anchor",href:"#爱尔夫罗伊德-elfroid","aria-label":'Permalink to "爱尔夫罗伊德（ELFROID）"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),d('<h1 id="爱尔夫罗伊德-elfroid-1" tabindex="-1">爱尔夫罗伊德（ELFROID） <a class="header-anchor" href="#爱尔夫罗伊德-elfroid-1" aria-label="Permalink to &quot;爱尔夫罗伊德（ELFROID）&quot;">​</a></h1><p>爱尔夫罗伊德（ELFROID）</p><p>特异本质<br> 一次性改造<br> 特殊的，该改造不会占据改造位</p><p>精灵——<br> 有着尖耳朵；<br> 性格冷酷；视情况也会出现性格温和的个体存在；<br> 长寿或者长生不老；<br> 高贵、骄傲、优雅，是一种身份高贵的种族；<br> 各项身体素质超过常人；<br> 和大自然贴近，通常生活在森林中，保持着孤立状态并且拒绝外来者；有些精灵能够和自然界的生物沟通。<br> 善良，爱好和平，敌视邪恶种族，但和善良种族和平相处；<br> 柔韧敏捷，擅长使用魔法和弓箭；<br> 精灵在一些方面经验丰富，在另一些方面却缺乏常识千岁巨婴；<br> 多半趋向同族通婚，但依照个别情况也会出现跨种恋的组合，所产下的混血后代被称作半精灵。</p><p>有这样一位少年，醉心于这动人的童话，废寝忘食，如痴如梦，<br> 在跨越种种困难之后，他终于找到了机种名为【精灵】的【魔像】，<br> 是的，精灵是古代人建造用于开发森林资源的铁魔像。</p><p>D+600</p><p>在兑换该改造后，轮回者的种族将转变为【魔像】，<br> 并且外观将会不可避免的改变：头部两侧延伸出一对宽大、扁平的机翼状机械耳；面部覆盖光滑的机械面罩，嵌着一对狭长的深色护目镜式眼部装置，无明显嘴部结构。<br> 身体是模块化拼接的机械装甲结构，胸口有分层的矩形装甲板，关节处暴露着齿轮 / 液压杆细节，装甲表面有磨损痕迹；四肢比例修长，手部是纤细的机械五指结构，腿部线条流畅，脚踝处有突出的机械部件。</p><p>在获得该改造时，从下列型号中选择一种，你获得对应的效果，一进选择无法更改：<br> 【达克】：偏重战斗的型号，在敏捷检定上获得生理属性中较低两者上的传奇属性之和的增强加值。<br> 【雪儿】：被称为傲慢的型号，在社交检定上受到2DP减值，额外获得5点外貌，在面对好感度不低于不满的单位时，令他们的好感度上升一级，不可达到极端。<br> 【艾尔达】：原始型号，该型号将会减少1点意志力上限，随后获得：一轮一次，将法术的消耗减少心智类传奇属性之和*1点（最低减少至1点）。</p><p>特殊的，在购买时可以额外支付3XP，你可以保留原有外观，或是改为森圣国时期的型号，<br> 若保留原有外观，则将基础外貌提升至5点，<br> 若将外观改为森圣国时期的型号，则将基础外貌以当前风度重新设定。</p><p>然后少年运用从冒险中学会的知识，技术，以及古代文明的力量，<br> 将精灵们的复古外表改装成了如今~（符合精灵刻板印象）~的新模样。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const D=a(n,[["render",s]]);export{f as __pageData,D as default};
